features.snippet:
virtual class base;
  virtual function void write(int t);
endclass
class impl extends base;
  function void write(int t);
    child.write(t);
  endfunction
endclass
class child extends base;
  virtual task write(int t);
    @(posedge clk);
  endtask
endclass

virtual class tlm_if;
  virtual function void write(input int t);
endclass
class analysis_imp extends tlm_if;
  local impl m_imp;
  function void write(input int t);
    m_imp.write(t);
  endfunction
endclass
class scoreboard;
  virtual task write(int t);
    @(posedge clk);
  endtask
endclass
